mapper.select:
select T.DM_CLCT_ID as clctId ,M.DM_ID as dataModelId ,M.DM_NM as dataModelNm ,M.DM_SYS_CD as dataModelSysCd ,(select SYS_NM from TB_SYS_INFO where sys_cd = M.DM_SYS_CD) as dataModelSysNm ,M.DM_DS_ID as dataModelDsId ,(select DSN from ndata.TB_DATA_SOURCE where ds_id = M.DM_DS_ID) as dataModelDsNm ,M.VER as dataModelVer ,to_char(to_timestamp(T.CLCT_START_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as clctStartDt ,to_char(to_timestamp(T.CLCT_END_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as clctEndDt ,T.CLCT_CMPTN_YN as clctCmptnYn from TB_DATA_MODEL_CLCT T, TB_DATA_MODEL M where T.DM_ID = M.DM_ID AND M.USE_YN = 'Y'
AND M.DM_ID = #{schId}
AND M.DM_NM ILIKE '%' || #{schNm} || '%'
AND M.DM_SYS_CD in (select SYS_CD from TB_SYS_INFO where SYS_NM ILIKE '%' || #{schSysNm} || '%')
AND T.CLCT_END_DT >= #{from}
AND T.CLCT_END_DT <= #{to}
order by T.CLCT_END_DT DESC NULLS LAST

select OBJ_NM as objNm ,OBJ_NM_KR as objNmKr ,OBJ_OWNER as objOwner ,OBJ_DESC as objDesc ,OBJ_ATTR_CNT as objAttrCnt from TB_DATA_MODEL_OBJ where DM_CLCT_ID = #{schId}
AND OBJ_NM ILIKE '%'||#{schObjNm}||'%'
order by OBJ_NM

SELECT DM_ID AS "dataModelId", DM_NM AS "dataModelNm", DM_DS_ID AS "dataModelDsId"
FROM TB_DATA_MODEL
WHERE DM_ID = #{dataModelId}

SELECT DM_CLCT_ID AS "clctId", CLCT_END_DT AS "clctEndDt"
FROM TB_DATA_MODEL_CLCT
WHERE DM_CLCT_ID = #{clctId}

select A.OBJ_NM ,(select OBJ_NM_KR from TB_DATA_MODEL_OBJ where DM_CLCT_ID = A.DM_CLCT_ID and OBJ_NM = A.OBJ_NM) as OBJ_NM_KR ,A.ATTR_NM ,A.ATTR_NM_KR ,A.DATA_TYPE ,A.DATA_LEN ,A.DATA_DECIMAL_LEN ,A.TERMS_STND_YN ,A.DOMAIN_STND_YN ,A.WORD_LST ,A.WORD_STND_LST ,A.NULLABLE_YN ,A.PK_YN ,A.FK_YN ,A.DEFAULT_VAL from TB_DATA_MODEL_ATTR A where A.DM_CLCT_ID = #{schId}
AND (A.OBJ_NM ILIKE '%'||#{schObjNm}||'%' OR A.ATTR_NM ILIKE '%'||#{schAttrNm}||'%')
AND A.TERMS_STND_YN = #{schStndYn}
order by A.OBJ_NM, A.ATTR_ORD

select T.DM_CLCT_ID as clctId ,M.DM_ID as dataModelId ,M.DM_NM as dataModelNm ,M.DM_SYS_CD as dataModelSysCd ,(select SYS_NM from TB_SYS_INFO where sys_cd = M.DM_SYS_CD) as dataModelSysNm ,M.DM_DS_ID as dataModelDsId ,(select DSN from ndata.TB_DATA_SOURCE where ds_id = M.DM_DS_ID) as dataModelDsNm ,M.VER as dataModelVer ,to_char(to_timestamp(T.CLCT_START_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as clctStartDt ,to_char(to_timestamp(T.CLCT_END_DT,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') as clctEndDt ,T.CLCT_CMPTN_YN as clctCmptnYn ,COALESCE(S.OBJ_CNT,0) as objCnt ,COALESCE(S.ATTR_CNT,0) as attrCnt ,COALESCE((SELECT ROUND( COUNT(*) FILTER (WHERE TERMS_STND_YN='Y' AND DOMAIN_STND_YN='Y')::NUMERIC / NULLIF(COUNT(*), 0) * 100, 1) FROM TB_DATA_MODEL_ATTR WHERE DM_CLCT_ID = T.DM_CLCT_ID), 0) as stndRate ,COALESCE((SELECT COUNT(*) FROM TB_DATA_MODEL_ATTR WHERE DM_CLCT_ID = T.DM_CLCT_ID AND NOT (TERMS_STND_YN='Y' AND DOMAIN_STND_YN='Y')), 0) as nonStndCnt ,COALESCE((SELECT COUNT(*) FROM TB_DATA_MODEL_ATTR WHERE DM_CLCT_ID = T.DM_CLCT_ID AND TERMS_STND_YN='N'), 0) as noTermsCnt ,COALESCE((SELECT COUNT(*) FROM TB_DATA_MODEL_ATTR WHERE DM_CLCT_ID = T.DM_CLCT_ID AND TERMS_STND_YN='Y' AND DOMAIN_STND_YN='N'), 0) as domainMismatchCnt from TB_DATA_MODEL_CLCT T JOIN TB_DATA_MODEL M on T.DM_ID = M.DM_ID LEFT OUTER JOIN TB_DATA_MODEL_STATS S on T.DM_CLCT_ID = S.DM_CLCT_ID where M.USE_YN = 'Y'
AND M.DM_NM ILIKE '%' || #{schNm} || '%'
AND M.DM_SYS_CD in (select SYS_CD from TB_SYS_INFO where SYS_NM ILIKE '%' || #{schSysNm} || '%')
AND T.CLCT_END_DT >= #{from}
AND T.CLCT_END_DT <= #{to}
order by T.CLCT_END_DT DESC NULLS LAST

mapper.insert:
INSERT INTO TB_DATA_MODEL
(
  DM_ID
 ,DM_NM			
 ,DM_SYS_CD
 ,DM_DS_ID		
 ,VER
 ,CRET_DT			
 ,CRET_USER_ID	
)
VALUES
(
  #{dataModelId}
 ,#{dataModelNm}
 ,#{dataModelSysCd}
 ,#{dataModelDsId}
 ,#{ver, jdbcType=VARCHAR}
 ,to_char(now(), 'YYYYMMDDHH24MISS')
 ,#{cretUserId, jdbcType=VARCHAR}
)

mapper.update:
UPDATE TB_DATA_MODEL
SET
  DM_NM = #{dataModelNm}
 ,DM_SYS_CD = #{dataModelSysCd}
 ,DM_DS_ID = #{dataModelDsId}
 ,VER = #{ver, jdbcType=VARCHAR}
 ,UPDT_DT = to_char(now(), 'YYYYMMDDHH24MISS')
 ,UPDT_USER_ID = #{updtUserId, jdbcType=VARCHAR}
where DM_ID = #{dataModelId}

mapper.insert:
           INSERT INTO TB_DATA_MODEL_CLCT	
           (
             DM_CLCT_ID
            ,DM_ID		
			,CLCT_START_DT
			,CRET_USER_ID
           )
           VALUES
           (
             #{clctId}
            ,#{dataModelId}
            ,to_char(now(), 'YYYYMMDDHH24MISS')
			,#{cretUserId, jdbcType=VARCHAR}
		   ) ON CONFLICT (DM_CLCT_ID,DM_ID) DO UPDATE
            SET 
              CLCT_END_DT = #{clctEndDt, jdbcType=VARCHAR}
			 ,CLCT_CMPTN_YN = #{clctCmptnYn, jdbcType=VARCHAR}

           INSERT INTO TB_DATA_MODEL_ATTR
           (
             DM_CLCT_ID
            ,DM_ID		
			,OBJ_NM
			,ATTR_NM
			,ATTR_NM_KR
			,DATA_TYPE
			,DATA_LEN
			,DATA_DECIMAL_LEN
			,TERMS_STND_YN
			,DOMAIN_STND_YN
			,WORD_LST
			,WORD_STND_LST
			,NULLABLE_YN
			,PK_YN
			,FK_YN
			,DEFAULT_VAL
			,ATTR_ORD
           )
           VALUES
           (
             #{clctId}
            ,#{dataModelId}
            ,#{objNm, jdbcType=VARCHAR}
            ,#{attrNm, jdbcType=VARCHAR}
			,#{attrNmKr, jdbcType=VARCHAR}
			,#{dataType, jdbcType=VARCHAR}
			,#{dataLen, jdbcType=BIGINT}
			,#{dataDecimalLen, jdbcType=SMALLINT}
			,#{termsStndYn, jdbcType=VARCHAR}
			,#{domainStndYn, jdbcType=VARCHAR}
			,#{wordLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
			,#{wordStndLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
			,#{nullableYn, jdbcType=VARCHAR}
			,#{pkYn, jdbcType=VARCHAR}
			,#{fkYn, jdbcType=VARCHAR}
			,#{defaultVal, jdbcType=VARCHAR}
			,#{attrOrder, jdbcType=SMALLINT}
		   )

           INSERT INTO TB_DATA_MODEL_OBJ	
           (
             DM_CLCT_ID
            ,DM_ID		
			,OBJ_NM
			,OBJ_NM_KR
			,OBJ_OWNER
			,OBJ_DESC
			,OBJ_ATTR_CNT
           )
           VALUES
           (
             #{clctId}
            ,#{dataModelId}
            ,#{objNm, jdbcType=VARCHAR}
			,#{objNmKr, jdbcType=VARCHAR}
			,#{objOwner, jdbcType=VARCHAR}
			,#{objDesc, jdbcType=VARCHAR}
			,#{objAttrCnt, jdbcType=SMALLINT}
		   )

INSERT INTO TB_DATA_MODEL_SCHEMA
(
	 DM_ID
	,SCHEMA_NM
	,USE_YN
	,CRET_DT
	,CRET_USER_ID
)
VALUES
(
	 #{dataModelId}
	,#{schemaNm}
	,#{useYn}
	,to_char(now(), 'YYYYMMDDHH24MISS')
	,#{cretUserId, jdbcType=VARCHAR}
)
ON CONFLICT (DM_ID, SCHEMA_NM) DO UPDATE
SET USE_YN = #{useYn}
